{"i": "Check special_approval on AR-02 records", "command": "sqlite3 /benchmark/data/expense.db "
SELECT special_approval, COUNT(*) FROM expense_records er
JOIN approvals a ON er.record_id = a.record_id
WHERE a.tier_id = 'AR-02'
GROUP BY special_approval;
""}

{"i": "Verify no AR-02 has 财务复核 in approvals", "command": "sqlite3 /benchmark/data/expense.db "
SELECT COUNT(*) FROM expense_records er
JOIN approvals a ON er.record_id = a.record_id
WHERE a.tier_id = 'AR-02' AND a.approver_role = '财务复核';
""}

